CREATE OR REPLACE FUNCTION document.list_brand_guides()
 RETURNS SETOF document.brand_guide
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT * FROM document.brand_guide
  WHERE tenant_id = current_setting('app.tenant_id', true)
  ORDER BY name;
END;
$function$;
COMMENT ON FUNCTION document.list_brand_guides() IS 'List all brand guides for current tenant';

CREATE OR REPLACE FUNCTION document.list_documents(p_params jsonb DEFAULT '{}'::jsonb)
 RETURNS SETOF document.document
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_doc_type text := NULLIF(trim(COALESCE(p_params->>'doc_type', '')), '');
  v_status   text := NULLIF(trim(COALESCE(p_params->>'status', '')), '');
  v_module   text := NULLIF(trim(COALESCE(p_params->>'ref_module', '')), '');
BEGIN
  RETURN QUERY
  SELECT *
  FROM document.document
  WHERE tenant_id = current_setting('app.tenant_id', true)
    AND (v_doc_type IS NULL OR doc_type = v_doc_type)
    AND (v_status IS NULL OR status = v_status)
    AND (v_module IS NULL OR ref_module = v_module)
  ORDER BY created_at DESC;
END;
$function$;
COMMENT ON FUNCTION document.list_documents(jsonb) IS 'List documents with optional filters (doc_type, status, ref_module)';

CREATE OR REPLACE FUNCTION document.list_templates(p_doc_type text DEFAULT NULL::text)
 RETURNS SETOF document.template
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN QUERY
  SELECT *
  FROM document.template
  WHERE tenant_id = current_setting('app.tenant_id', true)
    AND (p_doc_type IS NULL OR doc_type = p_doc_type)
  ORDER BY doc_type, name;
END;
$function$;
COMMENT ON FUNCTION document.list_templates(text) IS 'List templates, optionally filtered by doc_type';

CREATE OR REPLACE FUNCTION document.nav_items()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN jsonb_build_array(
    jsonb_build_object('href', '/', 'label', pgv.t('document.nav_documents'), 'icon', 'file-text'),
    jsonb_build_object('href', '/templates', 'label', pgv.t('document.nav_templates'), 'icon', 'layout'),
    jsonb_build_object('href', '/brand_guides', 'label', pgv.t('document.nav_brand_guides'), 'icon', 'palette'),
    jsonb_build_object('href', '/company', 'label', pgv.t('document.nav_company'), 'icon', 'building')
  );
END;
$function$;
COMMENT ON FUNCTION document.nav_items() IS 'Navigation items for document module (i18n)';

CREATE OR REPLACE FUNCTION document.post_canvas_delete(p_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  DELETE FROM document.canvas
  WHERE id = p_id AND tenant_id = current_setting('app.tenant_id', true);

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Canvas introuvable</template>';
  END IF;

  RETURN '<template data-toast="success">Canvas supprimé</template>'
      || '<template data-redirect="/"></template>';
END;
$function$;
COMMENT ON FUNCTION document.post_canvas_delete(uuid) IS 'Delete a canvas (POST action)';

CREATE OR REPLACE FUNCTION document.post_canvas_duplicate(p_source_id uuid)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src document.canvas;
  v_new_id uuid;
BEGIN
  SELECT * INTO v_src FROM document.canvas WHERE id = p_source_id AND tenant_id = current_setting('app.tenant_id', true);
  IF v_src IS NULL THEN
    RETURN '<template data-toast="error">Canvas introuvable</template>';
  END IF;

  v_new_id := document.canvas_duplicate(p_source_id, v_src.name || ' (copie)');

  RETURN '<template data-toast="success">Canvas dupliqué</template>'
      || '<template data-redirect="' || pgv.call_ref('get_canvas', jsonb_build_object('p_id', v_new_id)) || '"></template>';
END;
$function$;
COMMENT ON FUNCTION document.post_canvas_duplicate(uuid) IS 'Duplicate a canvas (POST action)';

CREATE OR REPLACE FUNCTION document.post_company_save(p_name text, p_siret text DEFAULT NULL::text, p_tva_intra text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_city text DEFAULT NULL::text, p_postal_code text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_website text DEFAULT NULL::text, p_mentions text DEFAULT NULL::text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM document.set_company(p_name, p_siret, p_tva_intra, p_address, p_city, p_postal_code, p_phone, p_email, p_website, p_mentions);
  RETURN '<template data-toast="success">' || pgv.t('document.toast_company_saved') || '</template>'
      || '<template data-redirect="/company"></template>';
END;
$function$;
COMMENT ON FUNCTION document.post_company_save(text,text,text,text,text,text,text,text,text,text) IS 'Save company info (POST action)';

CREATE OR REPLACE FUNCTION document.session_get(p_canvas_id uuid, p_user_id text DEFAULT document.current_user_id())
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.session;
BEGIN
  SELECT * INTO v_row FROM document.session WHERE canvas_id = p_canvas_id AND user_id = p_user_id;
  IF NOT FOUND THEN
    RETURN jsonb_build_object('selected_ids', '[]'::jsonb, 'phase', 'idle', 'zoom', 1, 'toast', null);
  END IF;
  RETURN jsonb_build_object(
    'selected_ids', v_row.selected_ids,
    'phase', v_row.phase,
    'zoom', v_row.zoom,
    'toast', v_row.toast
  );
END;
$function$;
COMMENT ON FUNCTION document.session_get(uuid,text) IS 'Get ephemeral session state for a canvas+user';

CREATE OR REPLACE FUNCTION document.canvas_get_state(p_canvas_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas jsonb;
  v_elements jsonb;
  v_gradients jsonb;
  v_session jsonb;
BEGIN
  SELECT jsonb_build_object(
    'id', c.id, 'name', c.name, 'format', c.format,
    'orientation', c.orientation, 'width', c.width, 'height', c.height,
    'background', c.background, 'category', c.category, 'meta', c.meta
  ) INTO v_canvas
  FROM document.canvas c
  WHERE c.id = p_canvas_id
    AND c.tenant_id = current_setting('app.tenant_id', true);

  IF v_canvas IS NULL THEN
    RETURN NULL;
  END IF;

  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', e.id, 'type', e.type, 'parent_id', e.parent_id,
      'sort_order', e.sort_order, 'name', e.name,
      'x', e.x, 'y', e.y, 'width', e.width, 'height', e.height,
      'x1', e.x1, 'y1', e.y1, 'x2', e.x2, 'y2', e.y2,
      'cx', e.cx, 'cy', e.cy, 'r', e.r, 'rx', e.rx_, 'ry', e.ry_,
      'opacity', e.opacity, 'rotation', e.rotation,
      'fill', e.fill, 'stroke', e.stroke,
      'stroke_width', e.stroke_width, 'stroke_dasharray', e.stroke_dasharray,
      'props', e.props, 'asset_id', e.asset_id
    ) ORDER BY e.sort_order
  ), '[]') INTO v_elements
  FROM document.element e
  WHERE e.canvas_id = p_canvas_id;

  SELECT COALESCE(jsonb_agg(
    jsonb_build_object(
      'id', g.id, 'type', g.type, 'angle', g.angle,
      'cx', g.cx, 'cy', g.cy, 'r', g.gr, 'stops', g.stops
    )
  ), '[]') INTO v_gradients
  FROM document.gradient g
  WHERE g.canvas_id = p_canvas_id;

  v_session := document.session_get(p_canvas_id);

  RETURN v_canvas || jsonb_build_object('elements', v_elements, 'gradients', v_gradients, 'session', v_session);
END;
$function$;
COMMENT ON FUNCTION document.canvas_get_state(uuid) IS 'Return full canvas state: metadata + elements + gradients + session';

CREATE OR REPLACE FUNCTION document.session_sync(p_canvas_id uuid, p_selected_ids jsonb DEFAULT '[]'::jsonb, p_phase text DEFAULT 'idle'::text, p_zoom real DEFAULT 1, p_user_id text DEFAULT document.current_user_id())
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO document.session (canvas_id, user_id, selected_ids, phase, zoom, updated_at)
  VALUES (p_canvas_id, p_user_id, p_selected_ids, p_phase, p_zoom, now())
  ON CONFLICT (canvas_id, user_id) DO UPDATE SET
    selected_ids = EXCLUDED.selected_ids,
    phase = EXCLUDED.phase,
    zoom = EXCLUDED.zoom,
    updated_at = now();
END;
$function$;
COMMENT ON FUNCTION document.session_sync(uuid,jsonb,text,real,text) IS 'Upsert ephemeral session state for a canvas+user';

CREATE OR REPLACE FUNCTION document.session_toast(p_canvas_id uuid, p_text text, p_level text DEFAULT 'info'::text, p_duration integer DEFAULT 3000, p_user_id text DEFAULT document.current_user_id())
 RETURNS void
 LANGUAGE plpgsql
AS $function$
BEGIN
  INSERT INTO document.session (canvas_id, user_id, toast, updated_at)
  VALUES (p_canvas_id, p_user_id, jsonb_build_object('text', p_text, 'level', p_level, 'duration', p_duration, 'at', now()), now())
  ON CONFLICT (canvas_id, user_id) DO UPDATE SET
    toast = jsonb_build_object('text', p_text, 'level', p_level, 'duration', p_duration, 'at', now()),
    updated_at = now();
END;
$function$;
COMMENT ON FUNCTION document.session_toast(uuid,text,text,integer,text) IS 'Set a toast message in the session for a canvas+user';

CREATE OR REPLACE FUNCTION document.set_company(p_name text, p_siret text DEFAULT NULL::text, p_tva_intra text DEFAULT NULL::text, p_address text DEFAULT NULL::text, p_city text DEFAULT NULL::text, p_postal_code text DEFAULT NULL::text, p_phone text DEFAULT NULL::text, p_email text DEFAULT NULL::text, p_website text DEFAULT NULL::text, p_mentions text DEFAULT NULL::text)
 RETURNS document.company
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tid text := current_setting('app.tenant_id', true);
  v_row document.company;
BEGIN
  INSERT INTO document.company (tenant_id, name, siret, tva_intra, address, city, postal_code, phone, email, website, mentions)
  VALUES (v_tid, p_name, p_siret, p_tva_intra, p_address, p_city, p_postal_code, p_phone, p_email, p_website, p_mentions)
  ON CONFLICT (tenant_id) DO UPDATE SET
    name = EXCLUDED.name,
    siret = EXCLUDED.siret,
    tva_intra = EXCLUDED.tva_intra,
    address = EXCLUDED.address,
    city = EXCLUDED.city,
    postal_code = EXCLUDED.postal_code,
    phone = EXCLUDED.phone,
    email = EXCLUDED.email,
    website = EXCLUDED.website,
    mentions = EXCLUDED.mentions
  RETURNING * INTO v_row;

  RETURN v_row;
END;
$function$;
COMMENT ON FUNCTION document.set_company(text,text,text,text,text,text,text,text,text,text) IS 'Upsert company info for current tenant';

GRANT USAGE ON SCHEMA document TO anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA document TO anon;

-- Schema: document_ut
CREATE SCHEMA IF NOT EXISTS document_ut;

CREATE OR REPLACE FUNCTION document_ut.test_canvas_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id uuid;
  v_row document.canvas;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Default A4 portrait
  v_id := document.canvas_create('Test A4');
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.id IS NOT NULL, 'canvas created');
  RETURN NEXT is(v_row.name, 'Test A4', 'name matches');
  RETURN NEXT is(v_row.format, 'A4', 'format A4');
  RETURN NEXT is(v_row.orientation, 'portrait', 'portrait');
  RETURN NEXT ok(v_row.width = 794, 'A4 width 794');
  RETURN NEXT ok(v_row.height = 1123, 'A4 height 1123');

  -- Landscape
  v_id := document.canvas_create('Test landscape', 'A4', 'paysage');
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.width > v_row.height, 'landscape width > height');

  -- Custom dimensions
  v_id := document.canvas_create('Custom', 'CUSTOM', 'portrait', 500, 800);
  SELECT * INTO v_row FROM document.canvas WHERE id = v_id;
  RETURN NEXT ok(v_row.width = 500, 'custom width');
  RETURN NEXT ok(v_row.height = 800, 'custom height');

  -- Cleanup
  DELETE FROM document.canvas WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_create() IS 'Test canvas creation with formats and dimensions';

CREATE OR REPLACE FUNCTION document_ut.test_canvas_duplicate()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_src_id uuid;
  v_dup_id uuid;
  v_src_state jsonb;
  v_dup_state jsonb;
  v_src_elem_ids jsonb;
  v_dup_elem_ids jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Create source canvas with elements
  v_src_id := document.canvas_create('Original');
  PERFORM document.element_add(v_src_id, 'rect', 0, '{"x":0,"y":0,"width":100,"height":50}'::jsonb);
  PERFORM document.element_add(v_src_id, 'text', 1, '{"x":10,"y":20}'::jsonb);

  -- Duplicate
  v_dup_id := document.canvas_duplicate(v_src_id, 'Copy');

  -- Verify canvas
  v_src_state := document.canvas_get_state(v_src_id);
  v_dup_state := document.canvas_get_state(v_dup_id);

  RETURN NEXT ok(v_dup_id IS NOT NULL, 'duplicate created');
  RETURN NEXT ok(v_dup_id != v_src_id, 'different canvas ID');
  RETURN NEXT is(v_dup_state->>'name', 'Copy', 'duplicate name');
  RETURN NEXT is(v_dup_state->>'format', v_src_state->>'format', 'same format');
  RETURN NEXT ok(
    jsonb_array_length(v_dup_state->'elements') = jsonb_array_length(v_src_state->'elements'),
    'same element count'
  );

  -- Verify element IDs are different
  SELECT jsonb_agg(e->>'id') INTO v_src_elem_ids FROM jsonb_array_elements(v_src_state->'elements') e;
  SELECT jsonb_agg(e->>'id') INTO v_dup_elem_ids FROM jsonb_array_elements(v_dup_state->'elements') e;
  RETURN NEXT ok(v_src_elem_ids != v_dup_elem_ids, 'element IDs are different');

  -- Cleanup
  DELETE FROM document.canvas WHERE id IN (v_src_id, v_dup_id);
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_duplicate() IS 'Test canvas_duplicate deep copies with new IDs';

CREATE OR REPLACE FUNCTION document_ut.test_canvas_get_state()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_group_id uuid;
  v_state jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('State test');

  -- Add group
  v_group_id := document.element_add(v_canvas_id, 'group', 0, '{"name":"header"}'::jsonb);

  -- Add child rect in group
  PERFORM document.element_add(v_canvas_id, 'rect', 1,
    jsonb_build_object('x',0,'y',0,'width',100,'height',50,'parent_id', v_group_id));

  -- Add standalone text
  PERFORM document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":200}'::jsonb);

  -- Get state
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(v_state IS NOT NULL, 'state returned');
  RETURN NEXT is(v_state->>'name', 'State test', 'canvas name in state');
  RETURN NEXT ok(v_state ? 'elements', 'has elements key');
  RETURN NEXT ok(v_state ? 'gradients', 'has gradients key');
  RETURN NEXT ok(jsonb_array_length(v_state->'elements') = 3, '3 elements (group + rect + text)');

  -- Verify group element has children via parent_id
  RETURN NEXT ok(
    (SELECT count(*) FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'parent_id' IS NOT NULL) = 1,
    '1 element has parent_id'
  );

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_canvas_get_state() IS 'Test canvas_get_state returns full state with nested elements';

CREATE OR REPLACE FUNCTION document_ut.test_company()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_row document.company;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Initially no company
  v_row := document.company_info();
  RETURN NEXT ok(v_row.id IS NULL, 'no company initially');

  -- Upsert: create
  v_row := document.set_company('Acme SAS', '12345678901234', 'FR12345678901', '1 rue Test', 'Paris', '75001', '0100000000', 'test@acme.fr', 'https://acme.fr', 'RCS Paris');
  RETURN NEXT ok(v_row.id IS NOT NULL, 'company created');
  RETURN NEXT is(v_row.name, 'Acme SAS', 'name matches');
  RETURN NEXT is(v_row.siret, '12345678901234', 'siret matches');
  RETURN NEXT is(v_row.city, 'Paris', 'city matches');

  -- Upsert: update
  v_row := document.set_company('Acme SAS Updated', '12345678901234');
  RETURN NEXT is(v_row.name, 'Acme SAS Updated', 'name updated');

  -- Get
  v_row := document.company_info();
  RETURN NEXT is(v_row.name, 'Acme SAS Updated', 'company_info returns updated');

  -- Cleanup
  DELETE FROM document.company WHERE tenant_id = 'test';
END;
$function$;
COMMENT ON FUNCTION document_ut.test_company() IS 'Test company upsert and retrieval';

CREATE OR REPLACE FUNCTION document_ut.test_current_user_id()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_uid text;
BEGIN
  -- Default (no app.user_id set): returns 'dev'
  PERFORM set_config('app.user_id', '', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'dev', 'default returns dev');

  -- With app.user_id set
  PERFORM set_config('app.user_id', 'test-user-42', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'test-user-42', 'returns app.user_id when set');

  -- Reset
  PERFORM set_config('app.user_id', '', true);
  v_uid := document.current_user_id();
  RETURN NEXT is(v_uid, 'dev', 'back to dev after reset');
END;
$function$;
COMMENT ON FUNCTION document_ut.test_current_user_id() IS 'Test current_user_id resolution: app.user_id > ''dev''';

CREATE OR REPLACE FUNCTION document_ut.test_data_documents()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tpl_id uuid;
  v_doc_id1 uuid;
  v_doc_id2 uuid;
  v_result jsonb;
  v_row jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup
  INSERT INTO document.template (name, doc_type) VALUES ('TPL test', 'facture')
  RETURNING id INTO v_tpl_id;

  INSERT INTO document.document (template_id, doc_type, title, status)
  VALUES (v_tpl_id, 'facture', 'Doc A', 'draft')
  RETURNING id INTO v_doc_id1;

  INSERT INTO document.document (template_id, doc_type, title, status)
  VALUES (v_tpl_id, 'devis', 'Doc B', 'generated')
  RETURNING id INTO v_doc_id2;

  -- Test: format
  v_result := document.data_documents('{}');
  RETURN NEXT ok(v_result ? 'rows', 'result has rows key');
  RETURN NEXT ok(v_result ? 'has_more', 'result has has_more key');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 2, 'at least 2 rows');

  -- Test: row has 7 columns (id, title, doc_type, ref_module, ref_id, status, created)
  v_row := (v_result->'rows')->0;
  RETURN NEXT ok(jsonb_array_length(v_row) = 7, 'each row has 7 columns');

  -- Test: status filter
  v_result := document.data_documents('{"p_status":"draft"}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'status filter works');

  -- Test: doc_type filter
  v_result := document.data_documents('{"p_doc_type":"devis"}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'doc_type filter works');

  -- Test: pagination
  v_result := document.data_documents('{"_size":1}');
  RETURN NEXT ok((v_result->>'has_more')::boolean, 'has_more true with size=1');

  v_result := document.data_documents('{"_size":1,"_offset":1}');
  RETURN NEXT ok(jsonb_array_length(v_result->'rows') >= 1, 'offset pagination works');

  -- Cleanup
  DELETE FROM document.document WHERE id IN (v_doc_id1, v_doc_id2);
  DELETE FROM document.template WHERE id = v_tpl_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_data_documents() IS 'Test data_documents cursor format, filters, and pagination';

CREATE OR REPLACE FUNCTION document_ut.test_document()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_tpl_id uuid;
  v_doc_id1 uuid;
  v_doc_id2 uuid;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Setup template
  INSERT INTO document.template (name, doc_type) VALUES ('TPL test', 'facture')
  RETURNING id INTO v_tpl_id;

  -- Insert documents
  INSERT INTO document.document (template_id, doc_type, ref_module, ref_id, title, status)
  VALUES (v_tpl_id, 'facture', 'quote', '42', 'Facture #001', 'draft')
  RETURNING id INTO v_doc_id1;

  INSERT INTO document.document (template_id, doc_type, ref_module, ref_id, title, status)
  VALUES (v_tpl_id, 'devis', 'quote', '43', 'Devis #010', 'generated')
  RETURNING id INTO v_doc_id2;

  -- List all
  SELECT count(*)::int INTO v_cnt FROM document.list_documents();
  RETURN NEXT ok(v_cnt >= 2, 'list_documents returns at least 2');

  -- Filter by type
  SELECT count(*)::int INTO v_cnt FROM document.list_documents('{"doc_type":"facture"}');
  RETURN NEXT ok(v_cnt >= 1, 'filter by doc_type works');

  -- Filter by status
  SELECT count(*)::int INTO v_cnt FROM document.list_documents('{"status":"generated"}');
  RETURN NEXT ok(v_cnt >= 1, 'filter by status works');

  -- Filter by module
  SELECT count(*)::int INTO v_cnt FROM document.list_documents('{"ref_module":"quote"}');
  RETURN NEXT ok(v_cnt >= 2, 'filter by ref_module works');

  -- Cleanup
  DELETE FROM document.document WHERE id IN (v_doc_id1, v_doc_id2);
  DELETE FROM document.template WHERE id = v_tpl_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_document() IS 'Test document CRUD and filtering';

CREATE OR REPLACE FUNCTION document_ut.test_element_add()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_elem_id uuid;
  v_row document.element;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Test elements');

  -- Add text
  v_elem_id := document.element_add(v_canvas_id, 'text', 0, '{"x":10,"y":20,"fill":"#000","name":"title"}'::jsonb);
  SELECT * INTO v_row FROM document.element WHERE id = v_elem_id;
  RETURN NEXT ok(v_row.id IS NOT NULL, 'text element created');
  RETURN NEXT ok(v_row.x = 10, 'text x=10');
  RETURN NEXT ok(v_row.y = 20, 'text y=20');
  RETURN NEXT is(v_row.fill, '#000', 'text fill');
  RETURN NEXT is(v_row.name, 'title', 'text name');

  -- Add rect
  v_elem_id := document.element_add(v_canvas_id, 'rect', 1, '{"x":0,"y":0,"width":100,"height":50,"fill":"#ff0000"}'::jsonb);
  SELECT * INTO v_row FROM document.element WHERE id = v_elem_id;
  RETURN NEXT ok(v_row.width = 100, 'rect width=100');
  RETURN NEXT ok(v_row.height = 50, 'rect height=50');

  -- Add line
  v_elem_id := document.element_add(v_canvas_id, 'line', 2, '{"x1":0,"y1":0,"x2":100,"y2":100}'::jsonb);
  SELECT * INTO v_row FROM document.element WHERE id = v_elem_id;
  RETURN NEXT ok(v_row.x1 = 0 AND v_row.x2 = 100, 'line geometry');

  -- Add circle
  v_elem_id := document.element_add(v_canvas_id, 'circle', 3, '{"cx":50,"cy":50,"r":25}'::jsonb);
  SELECT * INTO v_row FROM document.element WHERE id = v_elem_id;
  RETURN NEXT ok(v_row.r = 25, 'circle r=25');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_element_add() IS 'Test element_add for text, rect, line, circle';

CREATE OR REPLACE FUNCTION document_ut.test_element_constraints()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_ok boolean;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Test constraints');

  -- rect without width should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"height":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'rect without width rejected');

  -- line without x2/y2 should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'line', 0, '{"x1":0,"y1":0}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'line without x2/y2 rejected');

  -- circle without r should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'circle', 0, '{"cx":50,"cy":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'circle without r rejected');

  -- ellipse without rx/ry should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'ellipse', 0, '{"cx":50,"cy":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'ellipse without rx/ry rejected');

  -- text without x/y should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'text', 0, '{"fill":"#000"}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'text without x/y rejected');

  -- negative width should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":-10,"height":50}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'negative width rejected');

  -- path without d in props should fail
  BEGIN
    PERFORM document.element_add(v_canvas_id, 'path', 0, '{"fill":"#000"}'::jsonb);
    v_ok := false;
  EXCEPTION WHEN check_violation THEN
    v_ok := true;
  END;
  RETURN NEXT ok(v_ok, 'path without d rejected');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_element_constraints() IS 'Test CHECK constraints reject invalid geometry per element type';

CREATE OR REPLACE FUNCTION document_ut.test_element_move()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_group_id uuid;
  v_moved int;
  v_row document.element;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Move test');

  -- Create elements: rect, circle, line
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":10,"y":20,"width":100,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'circle', 1, '{"cx":50,"cy":60,"r":25}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'line', 2, '{"x1":0,"y1":0,"x2":100,"y2":100}'::jsonb);

  -- Group them
  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2, v_e3], 'movable');

  -- Move group by +10, +5
  v_moved := document.element_move(v_group_id, 10, 5);
  RETURN NEXT is(v_moved, 3, '3 elements moved');

  -- Verify rect moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.x = 20, 'rect x: 10+10=20');
  RETURN NEXT ok(v_row.y = 25, 'rect y: 20+5=25');

  -- Verify circle moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e2;
  RETURN NEXT ok(v_row.cx = 60, 'circle cx: 50+10=60');
  RETURN NEXT ok(v_row.cy = 65, 'circle cy: 60+5=65');

  -- Verify line moved
  SELECT * INTO v_row FROM document.element WHERE id = v_e3;
  RETURN NEXT ok(v_row.x1 = 10, 'line x1: 0+10=10');
  RETURN NEXT ok(v_row.y1 = 5, 'line y1: 0+5=5');
  RETURN NEXT ok(v_row.x2 = 110, 'line x2: 100+10=110');
  RETURN NEXT ok(v_row.y2 = 105, 'line y2: 100+5=105');

  -- Move single leaf
  v_moved := document.element_move(v_e1, -5, -5);
  RETURN NEXT is(v_moved, 1, '1 element moved (single)');
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.x = 15, 'rect x after second move: 20-5=15');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_element_move() IS 'Test element_move: group recursive + single leaf + all geometry types';

CREATE OR REPLACE FUNCTION document_ut.test_group_create()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_group_id uuid;
  v_row document.element;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Group test');

  -- Create 3 sibling elements
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'rect', 1, '{"x":60,"y":0,"width":50,"height":50}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":100}'::jsonb);

  -- Group first two
  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'my-group');

  -- Verify group exists
  SELECT * INTO v_row FROM document.element WHERE id = v_group_id;
  RETURN NEXT ok(v_row.id IS NOT NULL, 'group element created');
  RETURN NEXT is(v_row.type, 'group', 'type is group');
  RETURN NEXT is(v_row.name, 'my-group', 'group name');
  RETURN NEXT ok(v_row.parent_id IS NULL, 'group parent is null (root level)');

  -- Verify children reparented
  SELECT count(*)::int INTO v_cnt FROM document.element WHERE parent_id = v_group_id;
  RETURN NEXT is(v_cnt, 2, '2 children in group');

  -- Third element still at root
  SELECT * INTO v_row FROM document.element WHERE id = v_e3;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'third element still root');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_create() IS 'Test group_create: group siblings, verify parent_id';

CREATE OR REPLACE FUNCTION document_ut.test_group_dissolve()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid;
  v_group_id uuid;
  v_freed int;
  v_row document.element;
  v_grp_exists boolean;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Dissolve test');

  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'text', 1, '{"x":10,"y":10}'::jsonb);

  v_group_id := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'temp-group');

  -- Dissolve
  v_freed := document.group_dissolve(v_group_id);
  RETURN NEXT is(v_freed, 2, '2 children freed');

  -- Group element should be gone
  SELECT EXISTS(SELECT 1 FROM document.element WHERE id = v_group_id) INTO v_grp_exists;
  RETURN NEXT ok(NOT v_grp_exists, 'group element deleted');

  -- Children back to root
  SELECT * INTO v_row FROM document.element WHERE id = v_e1;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'child 1 back to root');
  SELECT * INTO v_row FROM document.element WHERE id = v_e2;
  RETURN NEXT ok(v_row.parent_id IS NULL, 'child 2 back to root');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_dissolve() IS 'Test group_dissolve: children reparented, group deleted';

CREATE OR REPLACE FUNCTION document_ut.test_group_nested()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_e1 uuid; v_e2 uuid; v_e3 uuid;
  v_g1 uuid; v_g2 uuid;
  v_state jsonb;
  v_nested_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Nested test');

  -- Create elements
  v_e1 := document.element_add(v_canvas_id, 'rect', 0, '{"x":0,"y":0,"width":50,"height":50}'::jsonb);
  v_e2 := document.element_add(v_canvas_id, 'rect', 1, '{"x":60,"y":0,"width":50,"height":50}'::jsonb);
  v_e3 := document.element_add(v_canvas_id, 'text', 2, '{"x":10,"y":100}'::jsonb);

  -- Group e1+e2 into g1
  v_g1 := document.group_create(v_canvas_id, ARRAY[v_e1, v_e2], 'outer');

  -- Group g1+e3 into g2 (nested: g2 contains g1 which contains e1,e2)
  v_g2 := document.group_create(v_canvas_id, ARRAY[v_g1, v_e3], 'wrapper');

  -- Verify state
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(jsonb_array_length(v_state->'elements') = 5, '5 elements total (2 groups + 3 shapes)');

  -- g2 is root
  RETURN NEXT ok(
    (SELECT e->>'parent_id' IS NULL FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_g2::text),
    'wrapper group at root'
  );

  -- g1 is child of g2
  RETURN NEXT ok(
    (SELECT e->>'parent_id' = v_g2::text FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_g1::text),
    'outer group inside wrapper'
  );

  -- e1 is child of g1
  RETURN NEXT ok(
    (SELECT e->>'parent_id' = v_g1::text FROM jsonb_array_elements(v_state->'elements') e WHERE e->>'id' = v_e1::text),
    'rect inside outer group'
  );

  -- Count elements with parent_id set
  SELECT count(*)::int INTO v_nested_cnt
  FROM jsonb_array_elements(v_state->'elements') e
  WHERE e->>'parent_id' IS NOT NULL;
  RETURN NEXT is(v_nested_cnt, 4, '4 elements have parent_id (g1, e1, e2, e3)');

  -- Cleanup
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_group_nested() IS 'Test nested groups: group inside group, verify state tree';

CREATE OR REPLACE FUNCTION document_ut.test_session_sync()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_state jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Session test');

  -- Default state (no session row)
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'idle', 'default phase is idle');
  RETURN NEXT ok((v_state->>'zoom')::real = 1, 'default zoom is 1');

  -- Sync
  PERFORM document.session_sync(v_canvas_id, '["id1","id2"]'::jsonb, 'selected', 1.5);
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'selected', 'phase updated to selected');
  RETURN NEXT ok((v_state->>'zoom')::real = 1.5, 'zoom updated to 1.5');
  RETURN NEXT ok(jsonb_array_length(v_state->'selected_ids') = 2, '2 selected ids');

  -- Update sync
  PERFORM document.session_sync(v_canvas_id, '[]'::jsonb, 'idle', 2.0);
  v_state := document.session_get(v_canvas_id);
  RETURN NEXT is(v_state->>'phase', 'idle', 'phase back to idle');
  RETURN NEXT ok(jsonb_array_length(v_state->'selected_ids') = 0, '0 selected ids');

  -- Cleanup
  DELETE FROM document.session WHERE canvas_id = v_canvas_id;
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_session_sync() IS 'Test session sync and get';

CREATE OR REPLACE FUNCTION document_ut.test_session_toast()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_canvas_id uuid;
  v_state jsonb;
  v_toast jsonb;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);
  v_canvas_id := document.canvas_create('Toast test');

  -- Set toast
  PERFORM document.session_toast(v_canvas_id, 'Element added', 'success', 2000);
  v_state := document.session_get(v_canvas_id);
  v_toast := v_state->'toast';

  RETURN NEXT ok(v_toast IS NOT NULL, 'toast is set');
  RETURN NEXT is(v_toast->>'text', 'Element added', 'toast text matches');
  RETURN NEXT is(v_toast->>'level', 'success', 'toast level matches');
  RETURN NEXT ok((v_toast->>'duration')::int = 2000, 'toast duration matches');
  RETURN NEXT ok(v_toast ? 'at', 'toast has timestamp');

  -- Canvas get_state includes session
  v_state := document.canvas_get_state(v_canvas_id);
  RETURN NEXT ok(v_state ? 'session', 'canvas_get_state has session key');
  RETURN NEXT is(v_state->'session'->'toast'->>'text', 'Element added', 'session toast in canvas state');

  -- Cleanup
  DELETE FROM document.session WHERE canvas_id = v_canvas_id;
  DELETE FROM document.canvas WHERE id = v_canvas_id;
END;
$function$;
COMMENT ON FUNCTION document_ut.test_session_toast() IS 'Test session toast and canvas_get_state integration';

CREATE OR REPLACE FUNCTION document_ut.test_template()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id1 uuid;
  v_id2 uuid;
  v_row document.template;
  v_cnt int;
BEGIN
  PERFORM set_config('app.tenant_id', 'test', true);

  -- Insert templates
  INSERT INTO document.template (name, doc_type, format, is_default)
  VALUES ('Facture standard', 'facture', 'A4', true)
  RETURNING id INTO v_id1;

  INSERT INTO document.template (name, doc_type, format)
  VALUES ('Devis premium', 'devis', 'A4')
  RETURNING id INTO v_id2;

  -- List all
  SELECT count(*)::int INTO v_cnt FROM document.list_templates();
  RETURN NEXT ok(v_cnt >= 2, 'list_templates returns at least 2');

  -- List by type
  SELECT count(*)::int INTO v_cnt FROM document.list_templates('facture');
  RETURN NEXT ok(v_cnt >= 1, 'list_templates filters by doc_type');

  -- Get by ID
  v_row := document.get_template(v_id1);
  RETURN NEXT is(v_row.name, 'Facture standard', 'get_template returns correct name');
  RETURN NEXT ok(v_row.is_default, 'is_default true');

  -- Cleanup
  DELETE FROM document.template WHERE id IN (v_id1, v_id2);
END;
$function$;
COMMENT ON FUNCTION document_ut.test_template() IS 'Test template CRUD operations';

