  v_so := v_so + 1;
  PERFORM document.element_add(v_c, 'text', v_so, jsonb_build_object('x',v_w/2,'y',276,'fill','#ffffff','name','details-price','fontSize',4,'fontStyle','italic','textAnchor','middle','content','390€ per person — Tout est inclus'));
  v_so := v_so + 1;

